INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-b20a8cf8-moex-00304', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '將已製成的玻璃表面加熱後快速而均勻冷卻，表面產生應變及表面張力的效應，使處理後的玻璃 不易破碎，若是破碎則裂成近似四邊形的小玻璃，比較沒有傷害性，通常用在汽車門窗等處，這 種玻璃是下列何者？', '["浮漂玻璃（Floatglass）", "回火玻璃（Temperedglass）", "疊層玻璃（Laminatedglass）", "板玻璃（Plateglass）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "3693ce52aabf", "answer_pdf_sha1": "1758385edbdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00305', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '於車禍現場採獲數個玻璃碎片，欲測定玻璃的密度與折射率，下列敘述何者錯誤？', '["調整混合液的密度與玻璃的密度相同，然後將混合液注入定容積的比重瓶，利用天秤秤取混合 液的質量，可算出混合液密度，即是玻璃密度", "利用液體的密度隨溫度升高而變大的性質來測定玻璃密度", "由顯微鏡觀察玻璃碎片時，Beckeline如果向碎片內部移動即表示碎片的折射率大於浸液", "由顯微鏡觀察玻璃碎片時使用單色光，當碎片與浸液的折射率相同時，則Beckeline消失"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "3693ce52aabf", "answer_pdf_sha1": "1758385edbdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00306', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '測量血液中酒精含量（BloodAlcoholConcentration；BAC）就可估計體內酒精總量。酒精經由血 液到達腦部對中樞神經系統作用，下列敘述何者錯誤？', '["隨著BAC的增高，自主功能系統逐漸受到影響", "BAC在0.09-0.25%情緒不穩，自制力減退，尚失基本的判斷力", "BAC≧0.45%可能引起呼吸器官的麻痺導致死亡", "BAC為0.05%時，表示每100mL呼氣內含200 μg酒精"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "3693ce52aabf", "answer_pdf_sha1": "1758385edbdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00307', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '犯罪者為隱瞞事實常將打印在金屬表面的字跡磨掉，鑑識人員使用電解法或化學腐蝕法還原字 跡，金屬物質上之打印字跡被磨滅的程度可以磨滅值（Removal depth；RD）來表示。下列敘述 何者錯誤？', '["打印金屬表面的字跡時，證物的金屬晶格被破壞程度與RD成正比", "若RD值越小則重現被磨滅號碼之可能性越大", "硬度較小之鋁合金的晶格比較容易被破壞，可顯現的RD極限可高達4", "硬度較大之鐵製品的晶格比較不容易被破壞，可顯現的RD極限約為2"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "3693ce52aabf", "answer_pdf_sha1": "1758385edbdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00308', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '歹徒常使用膠帶進行各項犯罪活動，因此，如何顯現膠帶黏膠面上指紋，對於破案有其重要性，', '["氰丙烯酸脂法燻蒸後再以 Basic Yellow 40 染料漂染", "氯化鋅試劑法（Zincchloridesolution）", "硝酸銀試劑法（Silvernitratesolution）", "碘燻法（Iodinevapor）  ⑤黏膠面粉末法（Sticky-sidepowder）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "3693ce52aabf", "answer_pdf_sha1": "1758385edbdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00309', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '在車禍肇事逃逸案，油漆常因碰撞被轉移至肇事車輛上，應使用何種方法鑑別轉移油漆與肇事車 輛油漆是否相符，下列鑑定方法敘述何者錯誤？', '["熱解氣相層析法（Pyrolysis-gaschromatography）藉由裂解產物之層析結果來鑑析該高分子的化 學組成與結構", "紅外線光譜法（Infraredspectroscopy）分析高分子聚合物與顏料成分之方法", "顯微分光光譜法（Microspectrophotomery）分析表面或橫切面各漆顏色，提供可見光光譜和顏 色色彩座標資料", "超微切片技術（Ultra-microtomy）可提供每一漆層之顏料及其分佈鑑定，樣品經浸泡丙酮後， 進行有機成分分析"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "3693ce52aabf", "answer_pdf_sha1": "1758385edbdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00310', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '鑑識人員若無經過完整訓練，可能會誤將Kastle-Meyer試劑的偽陽性反應當作陽性反應，下列何', '["含有強氧化劑的清潔劑", "植物過氧化酶", "酒 精", "蘋果、山葵、花椰菜  ⑤乙醚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "3693ce52aabf", "answer_pdf_sha1": "1758385edbdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00311', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '於湖泊發現有具浮屍，可檢驗浮屍體內的組織或器官等處是否含有矽藻，這些矽藻檢驗結果能提 供何種訊息給偵查人員參考，下列敘述何者錯誤？', '["研判生前落水", "研判死後棄屍", "研判落水水域", "研判死亡時間"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "3693ce52aabf", "answer_pdf_sha1": "1758385edbdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00312', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '犯罪現場常會發現許多纖維，鑑識人員欲鑑別天然纖維（包含植物及動物纖維）與人造纖維之差 異，下列何種鑑別方法最不適當？', '["偏光顯微鏡法，檢視這二類纖維偏光性之差異", "生物顯微鏡法，檢視這二類纖維外周面及橫切面型態之差異", "燃燒試驗法，檢視這二類纖維燃燒時情形、燃燒味道及灰燼型態之差異", "放射免疫擴散法，檢視這二類纖維抗體及抗原反應之差異"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "3693ce52aabf", "answer_pdf_sha1": "1758385edbdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00313', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '警方接獲民眾檢舉，在某郊區工寮經常發出惡臭，疑似有違法製造毒品情事，警方獲報後，出動 警力圍捕，經現場勘察人員發現大批的鄰-氯苯基環戊基酮原料，請問對於該工寮可能製造出毒 品之敘述，何者正確？', '["在製造卡西酮類毒品", "在製造愷他命類毒品", "在製造安非他命類毒品", "在製造古柯鹼類毒品"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "3693ce52aabf", "answer_pdf_sha1": "1758385edbdb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
